%======================================================================
\section{Group-Theoretic Structure and Electroweak Mass Eigenvalues}
\label{sec:grouptheory}
%======================================================================

The sBootstrap's field content---$\mathbf{24}+\mathbf{1}$ (mesons and
sleptons) plus $\mathbf{15}+\overline{\mathbf{15}}$ (diquarks and
squarks) of $SU(5)$ flavor---was noted in \S\ref{subsec:so32conn} to
match a decomposition of the $SO(32)$ adjoint.  In this section we
make that decomposition explicit and show that it combines naturally
with a mass eigenvalue equation built from the Poincar\'e Casimir
invariants, yielding a tree-level relation between $M_W$ and $M_Z$
that reproduces the on-shell weak mixing angle to $0.13\sigma$.

%----------------------------------------------------------------------
\subsection{The $SO(32)$ adjoint decomposition}
\label{subsec:so32decomp}
%----------------------------------------------------------------------

Consider the embedding chain
\begin{equation}
\label{eq:chain}
SO(32)\;\supset\;SU(16)\times U(1)_A
\;\supset\;SU(5)\times SU(3)\times U(1)_A\times U(1)_B\,.
\end{equation}
Under $SU(5)\times SU(3)$ the fundamental $\mathbf{32}$ decomposes as
\begin{equation}
\label{eq:fund32}
\mathbf{32}\;=\;\underbrace{(\mathbf{5},\mathbf{3})}_{R_1}
\;\oplus\;\underbrace{(\bar{\mathbf{5}},\bar{\mathbf{3}})}_{R_2}
\;\oplus\;\underbrace{(\mathbf{1},\mathbf{1})}_{R_3}
\;\oplus\;\underbrace{(\mathbf{1},\mathbf{1})}_{R_4}\,,
\end{equation}
with $\dim = 15+15+1+1 = 32$.  The two singlets $R_3,R_4$ carry
opposite $U(1)_A$ charges and are distinguished by $U(1)_B$.

The adjoint of $SO(32)$ is the antisymmetric square
$\wedge^2(\mathbf{32})$, of dimension $\binom{32}{2}=496$.
Its decomposition proceeds block by block.

\paragraph{Antisymmetric squares.}
\begin{align}
\wedge^2 R_1
&= \wedge^2(\mathbf{5},\mathbf{3})
= (\mathbf{10},\mathbf{6})\;\oplus\;
  (\overline{\mathbf{15}},\bar{\mathbf{3}})\,,
& \dim &= 60+45 = 105\,,
\label{eq:wedge_R1}
\\[4pt]
\wedge^2 R_2
&= \wedge^2(\bar{\mathbf{5}},\bar{\mathbf{3}})
= (\overline{\mathbf{10}},\bar{\mathbf{6}})\;\oplus\;
  (\mathbf{15},\mathbf{3})\,,
& \dim &= 60+45 = 105\,.
\label{eq:wedge_R2}
\end{align}
Here we use the standard identities
$\wedge^2(\mathbf{5})=\mathbf{10}$,
$\mathrm{Sym}^2(\mathbf{5})=\mathbf{15}$, and
$\wedge^2(\mathbf{5}\otimes\mathbf{3})
 =[\wedge^2(\mathbf{5})\otimes\mathrm{Sym}^2(\mathbf{3})]
 \oplus[\mathrm{Sym}^2(\mathbf{5})\otimes\wedge^2(\mathbf{3})]$,
together with $\mathrm{Sym}^2(\mathbf{3})=\mathbf{6}$,
$\wedge^2(\mathbf{3})=\bar{\mathbf{3}}$.

\paragraph{Mixed tensor products.}
\begin{equation}
R_1\otimes R_2
= (\mathbf{5},\mathbf{3})\otimes
  (\bar{\mathbf{5}},\bar{\mathbf{3}})
= (\mathbf{24},\mathbf{8})
  \;\oplus\;(\mathbf{24},\mathbf{1})
  \;\oplus\;(\mathbf{1},\mathbf{8})
  \;\oplus\;(\mathbf{1},\mathbf{1})\,,
\quad\dim = 192+24+8+1 = 225\,.
\label{eq:R1R2}
\end{equation}
This is $(\mathbf{5}\otimes\bar{\mathbf{5}})
\otimes(\mathbf{3}\otimes\bar{\mathbf{3}})
= (\mathbf{24}\oplus\mathbf{1})\otimes(\mathbf{8}\oplus\mathbf{1})$.
The remaining cross terms are
\begin{equation}
R_1\otimes R_3,\;R_1\otimes R_4:\;
2\times(\mathbf{5},\mathbf{3}),\quad
R_2\otimes R_3,\;R_2\otimes R_4:\;
2\times(\bar{\mathbf{5}},\bar{\mathbf{3}}),\quad
R_3\otimes R_4:\;(\mathbf{1},\mathbf{1})\,.
\label{eq:cross}
\end{equation}
Collecting dimensions: $105+105+225 + 2\!\cdot\!15+2\!\cdot\!15+1
= 496$.  The complete decomposition, with $U(1)$ charges, is
displayed in Table~\ref{tab:so32adj}.

\begin{table}[t]
\centering
\caption{Decomposition of the $SO(32)$ adjoint $\wedge^2(\mathbf{32})$
under $SU(5)\times SU(3)\times U(1)_A\times U(1)_B$.  Charges $Q_A$
and $Q_B$ are normalized so that $R_1$ carries $(Q_A,Q_B)=(+1,+1)$.}
\label{tab:so32adj}
\smallskip
\begin{tabular}{lcrrl}
\toprule
Representation & Dim & $Q_A$ & $Q_B$ & Origin \\
\midrule
$(\mathbf{24},\mathbf{8})$ & 192 & $0$ & $0$ & $R_1\otimes R_2$ \\
$(\mathbf{24},\mathbf{1})$ &  24 & $0$ & $0$ & $R_1\otimes R_2$ \\
$(\mathbf{1},\mathbf{8})$  &   8 & $0$ & $0$ & $R_1\otimes R_2$ \\
$(\mathbf{1},\mathbf{1})$  &   2 & $0$ & $0$
   & $R_1\!\otimes\!R_2\,+\,R_3\!\otimes\!R_4$ \\[3pt]
$(\mathbf{10},\mathbf{6})$ &  60 & $+2$ & $+2$ & $\wedge^2(R_1)$ \\
$(\overline{\mathbf{10}},\bar{\mathbf{6}})$ & 60 & $-2$ & $-2$
   & $\wedge^2(R_2)$ \\
$(\overline{\mathbf{15}},\bar{\mathbf{3}})$ & 45 & $+2$ & $+2$
   & $\wedge^2(R_1)$ \\
$(\mathbf{15},\mathbf{3})$ & 45 & $-2$ & $-2$ & $\wedge^2(R_2)$ \\[3pt]
$(\mathbf{5},\mathbf{3})$  & $2\!\times\!15$ & $\pm 2,0$ & varies
   & $R_1\!\otimes\!R_3,\;R_1\!\otimes\!R_4$ \\
$(\bar{\mathbf{5}},\bar{\mathbf{3}})$ & $2\!\times\!15$ & varies
   & varies & $R_2\!\otimes\!R_3,\;R_2\!\otimes\!R_4$ \\
\bottomrule
\end{tabular}
\end{table}

The \emph{neutral sector}---states with $Q_A=Q_B=0$---has
dimension $192+24+8+2 = 226$.  This equals
$\dim\,SU(15)+2 = 224+2$, accounting for the adjoint of the
commutant $SU(15)\subset SO(32)$ together with the two abelian
generators $U(1)_A$ and $U(1)_B$.  The remaining $496-226=270$
states carry nonzero $U(1)$ charges and include the
$\mathbf{15}+\overline{\mathbf{15}}$ that, in the sBootstrap
interpretation, house the diquark and squark degrees of freedom.

%----------------------------------------------------------------------
\subsection{Poincar\'e Casimir mass eigenvalues}
\label{subsec:casimir}
%----------------------------------------------------------------------

The Poincar\'e group $ISO(3,1)$ has two Casimir invariants.  On a
massive one-particle state of mass $M$ and spin $s$ they take the
values
\begin{equation}
C_1 = P_\mu P^\mu = M^2\,,\qquad
C_2 = W_\mu W^\mu = -M^2\,s(s+1)\,,
\label{eq:casimirs}
\end{equation}
where $W^\mu$ is the Pauli--Lubanski pseudovector.  These label the
unitary irreducible representations of the Poincar\'e group and
therefore specify the kinematic identity of every particle.

Consider the eigenvalue equation that results from treating $C_1$ and
$C_2$ as operators acting on a common mass scale $m$:
\begin{equation}
\boxed{\;x^2 + C\,x - C = 0\,,\qquad
x \equiv \frac{M^2}{m^2}\,,\quad C \equiv s(s+1)\,.\;}
\label{eq:masseq}
\end{equation}
The same polynomial arises from a classical de~Broglie standing-wave
condition.  Requiring the relativistic velocity parameter $\beta$ to
satisfy
\begin{equation}
\frac{\beta^2}{\sqrt{1-\beta^2}} = \sqrt{s(s+1)}\,,
\label{eq:deBroglie}
\end{equation}
and substituting $x=\beta^2$, one obtains
$x^4/(1-x^2) = s(s+1)$, which rearranges to the same quadratic
\eqref{eq:masseq} after squaring and collecting terms.  The quantum
and classical routes converge on a single algebraic object.

\paragraph{Positive roots.}
The discriminant of \eqref{eq:masseq} is $C^2+4C = C(C+4)>0$ for
$C>0$, giving two real roots
\begin{equation}
x_\pm = \frac{-C \pm \sqrt{C^2+4C}}{2}\,.
\label{eq:roots}
\end{equation}
For $C>0$ one root is positive ($x_+$) and one negative ($x_-$).
Explicitly:
\begin{alignat}{3}
s &= 1:&\qquad
x_+ &= \sqrt{3}-1\,,&\qquad
x_- &= -1-\sqrt{3}\,,
\label{eq:s1roots}\\[4pt]
s &= \tfrac{1}{2}:&\qquad
x_+ &= \frac{-3+\sqrt{57}}{8}\,,&\qquad
x_- &= \frac{-3-\sqrt{57}}{8}\,.
\label{eq:s12roots}
\end{alignat}
Vieta's formulae give $x_+\,x_-=-C$ and $x_++x_-=-C$ in each case,
confirming that the product of eigenvalues is controlled by spin
alone.

%----------------------------------------------------------------------
\subsection{The mass ratio and the weak mixing angle}
\label{subsec:ratio}
%----------------------------------------------------------------------

Define the ratio of positive eigenvalues:
\begin{equation}
R \;\equiv\; 1 - \frac{x_+(s=\tfrac{1}{2})}{x_+(s=1)}
\;=\; 1 - \frac{M^2(s=\tfrac{1}{2},+)}{M^2(s=1,+)}\,.
\label{eq:Rdef}
\end{equation}
Substituting \eqref{eq:s1roots}--\eqref{eq:s12roots} and
rationalizing:
\begin{align}
R &= 1 - \frac{(-3+\sqrt{57})/8}{\sqrt{3}-1}
\;=\; 1 - \frac{(-3+\sqrt{57})(\sqrt{3}+1)}{16}
\notag\\[4pt]
&= \frac{19 + 3\sqrt{3} - 3\sqrt{19} - \sqrt{57}}{16}
\;=\; \frac{(\sqrt{19}-3)(\sqrt{19}-\sqrt{3}\,)}{16}\,.
\label{eq:Rclosed}
\end{align}
Numerically,
\begin{equation}
R = 0.223\,101\,322\,300\,866\ldots
\label{eq:Rnum}
\end{equation}
This is a degree-4 algebraic number over~$\mathbb{Q}$; its minimal
polynomial is
\begin{equation}
64\,t^4 - 304\,t^3 + 414\,t^2 - 190\,t + 25 = 0\,.
\label{eq:minpoly}
\end{equation}
One verifies \eqref{eq:minpoly} by noting that $R$ lies in
$\mathbb{Q}(\sqrt{3},\sqrt{19})$, a biquadratic extension of degree~4,
and computing the norm $\prod_{\sigma}(t-\sigma(R))$ over the four
Galois automorphisms $\sqrt{3}\mapsto\pm\sqrt{3}$,
$\sqrt{19}\mapsto\pm\sqrt{19}$.

\paragraph{Comparison with the weak mixing angle.}
The on-shell definition of the weak mixing angle is
\begin{equation}
\sin^2\!\theta_W^{\text{os}}
\;\equiv\; 1 - \frac{M_W^2}{M_Z^2}
\;=\; 0.22306 \pm 0.00033\,.
\label{eq:sin2os}
\end{equation}
Comparing with \eqref{eq:Rnum}:
\begin{equation}
R - \sin^2\!\theta_W^{\text{os}} = +0.00004\,,\qquad
\frac{|R-\sin^2\!\theta_W^{\text{os}}|}{\sigma}
= 0.13\,.
\label{eq:Rtension}
\end{equation}
The agreement is striking: $R$ reproduces the on-shell weak mixing
angle to well within one standard deviation.

\paragraph{Renormalization scheme.}
It is essential to compare $R$ with the \emph{on-shell} value
rather than the $\overline{\text{MS}}$ running coupling
$\sin^2\!\hat\theta_W(M_Z) = 0.23122$, which differs by $36\sigma$.
The reason is structural: $R$ is defined as a ratio of mass
eigenvalues---it is a tree-level kinematic quantity that refers to
pole masses, not to running couplings evaluated at a renormalization
point.  The on-shell definition
$\sin^2\!\theta_W = 1 - M_W^2/M_Z^2$ is the natural counterpart
because it, too, is built from physical pole masses and carries no
scheme dependence.

%----------------------------------------------------------------------
\subsection{The electroweak mass spectrum}
\label{subsec:spectrum}
%----------------------------------------------------------------------

Setting $M(s\!=\!1,+) = M_Z = 91.188\GeV$ as input determines
the fundamental scale $m$ via $M_Z^2 = m^2(\sqrt{3}-1)$, and
all other eigenvalues follow.  The four states and their physical
comparisons are collected in Table~\ref{tab:spectrum}.

\begin{table}[t]
\centering
\caption{Mass spectrum from the Poincar\'e Casimir eigenvalue equation
$x^2+Cx-C=0$, with $M(1,+)=M_Z$ as input.}
\label{tab:spectrum}
\smallskip
\begin{tabular}{llcll}
\toprule
State & Exact form & Mass (GeV) & Comparison & Tension \\
\midrule
$M(1,+)$
  & $m\sqrt{\sqrt{3}-1}$
  & $91.188$
  & $M_Z = 91.188$
  & input \\[3pt]
$M(\tfrac{1}{2},+)$
  & $m\!\left[\tfrac{-3+\sqrt{57}}{8}\right]^{1/2}$
  & $80.374$
  & $M_W = 80.369\pm0.013$
  & $0.39\sigma$ \\[3pt]
$|M(1,-)|$
  & $m\sqrt{1+\sqrt{3}}$
  & $176.16$
  & $v/\!\sqrt{2} = 174.10$
  & $1.2\%$ \\[3pt]
$|M(\tfrac{1}{2},-)|$
  & $m\!\left[\tfrac{3+\sqrt{57}}{8}\right]^{1/2}$
  & $122.39$
  & $M_H = 125.25$
  & $2.3\%$ \\
\bottomrule
\end{tabular}
\end{table}

Several features deserve comment.

\begin{enumerate}
\item \textbf{$\boldsymbol{M_W}$ from $\boldsymbol{M_Z}$.}
  The spin-1 and spin-$\tfrac{1}{2}$ positive eigenvalues stand in
  the ratio $M_W^2/M_Z^2 = 1-R$, recovering the $W$ mass to
  $0.39\sigma$.  The quantity $R$ is not a fitted parameter but a
  consequence of the polynomial.

\item \textbf{The negative-root scale.}
  The negative eigenvalue $x_-(s\!=\!1)=-1-\sqrt{3}$ yields
  $|M(1,-)| = M_Z(1+\sqrt{3})^{1/2}/(\sqrt{3}-1)^{1/2}
  = M_Z\!\cdot\!(1+\sqrt{3})/\sqrt{2}\approx 176\GeV$, close to the
  electroweak vacuum expectation value $v/\sqrt{2}\approx 174\GeV$.

\item \textbf{Spin mismatch for $\boldsymbol{M_H}$.}
  The eigenvalue $|M(\tfrac{1}{2},-)|\approx 122\GeV$ lies $2.3\%$
  below the Higgs mass.  However, the Higgs boson has spin~0 while
  this state carries $s=\tfrac{1}{2}$.  Whether this near-coincidence
  is accidental or points to a deeper spin--mass relation remains an
  open question.
\end{enumerate}

%----------------------------------------------------------------------
\subsection{Uniqueness of the quartic}
\label{subsec:uniqueness}
%----------------------------------------------------------------------

The eigenvalue equation \eqref{eq:masseq} is the simplest member of
the family
\begin{equation}
x^2 + f(C)\,x + g(C) = 0\,,
\label{eq:genfamily}
\end{equation}
with $f$ and $g$ linear in $C=s(s+1)$:
\begin{equation}
f(C) = f_0 + f_1\,C\,,\qquad
g(C) = g_0 + g_1\,C\,.
\label{eq:fg}
\end{equation}
This is a four-parameter family $(f_0,f_1,g_0,g_1)$.
Three structural constraints pin the polynomial to \eqref{eq:masseq}:
\begin{enumerate}
\item $f_0 = 0$: no spin-independent mass term in the linear
  coefficient.  Without this, a constant shift in $M^2$ would be
  present even at $C=0$, violating the requirement that spinless
  representations decouple from the mass equation.

\item $g_0 = 0$: masslessness at $C=0$.  When $s(s+1)=0$ the
  equation must admit $x=0$, ensuring that the scalar sector does not
  acquire mass from this mechanism alone.

\item $g_1 = -f_1$: coefficient antisymmetry.  This is the condition
  that makes the constant term the negative of the linear term
  (both proportional to~$C$), enforcing a Vieta relation
  $x_+\,x_- = -C$ that ties the product of eigenvalues to spin.
\end{enumerate}
After normalization ($f_1=1$), these three conditions fully
determine $(f_0,f_1,g_0,g_1) = (0,1,0,-1)$.  The ratio
$R = 0.22310\ldots$ then \emph{follows} as a consequence; it is
not an additional free parameter.

The constraints are algebraically natural but require
first-principles justification.  Constraint~(1) demands that the
linear coefficient is purely a spin effect---plausible if the
equation descends from a representation-theoretic eigenvalue problem.
Constraint~(2) is a consistency condition at the boundary of the
spin spectrum.  Constraint~(3) is the deepest: it asserts a
duality between the two roots that may reflect CPT or some
target-space symmetry of the underlying string.  A derivation from
the $SO(32)$ Casimir structure would close the argument.

